const webhookItem = $input.item;
const binaryData = webhookItem.binary || {};
const jsonData = webhookItem.json || {};

const OPENAI_CONFIG = {
  generation_model: "gpt-image-2",
  analysis_model: "gpt-5.5",
  generation_endpoint: "https://api.openai.com/v1/images/edits",
  analysis_endpoint: "https://api.openai.com/v1/responses",
  image_size: "1024x1024",
  image_quality: "medium",
  analysis_reasoning_effort: "medium",
  analysis_text_verbosity: "medium"
};

const productImageBinary = binaryData['product_image'];
if (!productImageBinary) throw new Error('Missing product_image in webhook payload');

const productInfoText = String(jsonData['product_info'] || '').trim();
if (!productInfoText) throw new Error('Missing product_info text in webhook payload');

const competitorKeys = Object.keys(binaryData)
  .filter(k => k.startsWith('competitor_image_'))
  .sort((a, b) => {
    const na = parseInt(a.replace('competitor_image_', ''), 10);
    const nb = parseInt(b.replace('competitor_image_', ''), 10);
    return na - nb;
  });

if (!competitorKeys.length) throw new Error('No competitor_image_N fields found in webhook payload');

return competitorKeys.map((key, i) => ({
  json: {
    openai: OPENAI_CONFIG,
    slot: i + 1,
    slot_key: 'competitor ' + (i + 1),
    competitor_filename: binaryData[key].fileName || ('competitor_' + (i + 1) + '.jpg'),
    output_filename: 'generated_image_' + (i + 1) + '.png',
    productInfo: { description: productInfoText },
    product_info_raw: { description: productInfoText },
    product_info_ready: true,
    product_image_ready: true,
    competitor_image_ready: true
  },
  binary: {
    product_image: productImageBinary,
    competitor_image: binaryData[key]
  }
}));

const inputItems = $input.all();

const STAGE_1_PROMPT = `
Analyze the competitor listing image and compare it against the Product Info document.

Your goal is to identify the competitor image's REAL communication strategy,
then adapt that strategy safely using only supported product information.

The competitor image defines:
- the communication topic
- the buyer takeaway
- the visual storytelling direction

Product Info defines:
- factual correctness
- supported capabilities
- supported implementations
- supported claims

Do not invent new marketing angles that are not central to the competitor image.

Do not oversimplify the competitor image into a generic product-category message.

Distinguish between:
- the surface-level product topic
vs
- the deeper buyer-facing communication strategy.

Identify:

- the main communication strategy
- the core buyer takeaway
- the key visual priorities
- the information hierarchy
- the storytelling structure
- the features being emphasized
- unsupported claims/features
- the closest supported replacements from Product Info

Core Communication Focus ->
Identify the SINGLE most important communication goal of the competitor image.

Then identify:
- which supported product capabilities are ESSENTIAL to that message
- which supported capabilities should be EXCLUDED because they are unrelated to the competitor image's main idea

Communication-Relevant Supported Features ->
Identify ONLY the supported product capabilities from Product Info that are:
- fully supported
- visually communicable
- directly relevant to the competitor image's core communication goal

A supported feature does NOT automatically belong in the image.

Keep the response structured, concise, and practical.

Return the response as markdown text only.
`.trim();

const outputItems = [];

for (let i = 0; i < inputItems.length; i++) {
  const item = inputItems[i];

  if (!item.binary?.competitor_image) {
    throw new Error(`competitor_image binary missing on item ${i}`);
  }

  const competitorBuf = await this.helpers.getBinaryDataBuffer(i, "competitor_image");
  const competitorMime = item.binary.competitor_image.mimeType || "image/jpeg";
  const competitorDataUrl = `data:${competitorMime};base64,${competitorBuf.toString("base64")}`;

  const productInfoText = JSON.stringify(item.json.productInfo || {}, null, 2);

  const fullPrompt = `${STAGE_1_PROMPT}\n\n==============================\nPRODUCT INFO DOCUMENT\nThis is the source of truth for supported claims, specs, features, materials, and product behavior.\n==============================\n\n${productInfoText}\n\n==============================\nFINAL STAGE 1 CHECK\nAnalyze the competitor image's communication strategy, then safely adapt it using Product Info.\n==============================`;

  const body = {
    model: item.json.openai?.analysis_model || "gpt-5.5",
    reasoning: { effort: item.json.openai?.analysis_reasoning_effort || "medium" },
    text: { verbosity: item.json.openai?.analysis_text_verbosity || "medium" },
    input: [{
      role: "user",
      content: [
        { type: "input_text", text: fullPrompt },
        { type: "input_image", image_url: competitorDataUrl }
      ]
    }]
  };

  outputItems.push({
    json: {
      ...item.json,
      active_prompt: fullPrompt,
      stage1_prompt: STAGE_1_PROMPT,
      stage1_full_prompt: fullPrompt,
      stage1_request_body: body
    },
    binary: item.binary
  });
}

return outputItems;

function extractResponsesText(response, stageName) {
  if (!response) return "";
  if (typeof response.output_text === "string" && response.output_text.trim()) return response.output_text.trim();
  if (Array.isArray(response.output)) {
    const parts = [];
    for (const outputItem of response.output) {
      if (!outputItem || !Array.isArray(outputItem.content)) continue;
      for (const contentItem of outputItem.content) {
        if (!contentItem) continue;
        if (contentItem.type === "output_text" && typeof contentItem.text === "string") parts.push(contentItem.text);
        if (contentItem.type === "text" && typeof contentItem.text === "string") parts.push(contentItem.text);
      }
    }
    if (parts.length) return parts.join("\n").trim();
  }
  function fallbackFindText(x) {
    if (x == null) return "";
    if (typeof x === "string") return x;
    if (Array.isArray(x)) return x.map(fallbackFindText).filter(Boolean).join("\n");
    if (typeof x === "object") {
      if (x.output_text) return fallbackFindText(x.output_text);
      if (x.text) return fallbackFindText(x.text);
      if (x.content) return fallbackFindText(x.content);
      if (x.output) return fallbackFindText(x.output);
      if (x.message) return fallbackFindText(x.message);
      return Object.values(x).map(fallbackFindText).filter(Boolean).join("\n");
    }
    return String(x);
  }
  const fallbackText = fallbackFindText(response).trim();
  if (fallbackText) return fallbackText;
  throw new Error(`Could not extract ${stageName} text from OpenAI response. Preview: ` + JSON.stringify(response).slice(0, 2000));
}

const responses = $input.all();
const requestItems = $("Build Stage 1 - Competitor Strategy Analysis Request1").all();

return responses.map((responseItem, i) => {
  const originalItem = requestItems[i];
  if (!originalItem) throw new Error(`Matching Stage 1 request item not found for item ${i}`);
  const text = extractResponsesText(responseItem.json, "Stage 1 Competitor Strategy Analysis");
  return {
    json: {
      ...originalItem.json,
      stage1_competitor_strategy_analysis: text,
      stage1_output_markdown: text,
      stage1_raw_preview: JSON.stringify(responseItem.json).slice(0, 3000)
    },
    binary: originalItem.binary
  };
});

const inputItems = $input.all();

const STAGE_2_PROMPT = `
Using the real product photo, Product Info document, and competitor strategy analysis, create a SAFE generation brief.

Focus only on:
- preserving real product accuracy
- preventing hallucinated physical details
- preventing unsupported claims/features
- preserving visible screen/icons if present
- keeping only the supported information that is directly relevant to the competitor image's PRIMARY communication goal

The competitor image defines the communication topic and communication structure.
Product Info defines the correct factual content.
Stage 1 defines the supported adaptation direction.

Do not infer hidden functionality from the competitor image.
Do NOT give layout, composition, or art direction instructions.

If the competitor image does NOT use communication text as a dominant part of the image structure,
the SAFE brief must NOT include taglines, feature labels, specifications, callouts, or instructional text.

Keep the response short, practical, and specific.
Return markdown text only.
`.trim();

const outputItems = [];

for (let i = 0; i < inputItems.length; i++) {
  const item = inputItems[i];

  if (!item.binary?.product_image) throw new Error(`product_image binary missing on item ${i}`);
  if (!item.binary?.competitor_image) throw new Error(`competitor_image binary missing on item ${i}`);

  const productBuf = await this.helpers.getBinaryDataBuffer(i, "product_image");
  const competitorBuf = await this.helpers.getBinaryDataBuffer(i, "competitor_image");

  const productMime = item.binary.product_image.mimeType || "image/jpeg";
  const competitorMime = item.binary.competitor_image.mimeType || "image/jpeg";
  const productDataUrl = `data:${productMime};base64,${productBuf.toString("base64")}`;
  const competitorDataUrl = `data:${competitorMime};base64,${competitorBuf.toString("base64")}`;

  const productInfoText = JSON.stringify(item.json.productInfo || {}, null, 2);
  const stage1Text = item.json.stage1_competitor_strategy_analysis || item.json.stage1_output_markdown || "";

  const fullPrompt = `${STAGE_2_PROMPT}\n\n==============================\nPRODUCT INFO DOCUMENT\n==============================\n\n${productInfoText}\n\n==============================\nCOMPETITOR STRATEGY ANALYSIS FROM STAGE 1\n==============================\n\n${stage1Text}\n\n==============================\nFINAL SAFE BRIEF CHECK\n==============================`;

  const body = {
    model: item.json.openai?.analysis_model || "gpt-5.5",
    reasoning: { effort: item.json.openai?.analysis_reasoning_effort || "medium" },
    text: { verbosity: item.json.openai?.analysis_text_verbosity || "medium" },
    input: [{
      role: "user",
      content: [
        { type: "input_text", text: fullPrompt },
        { type: "input_image", image_url: productDataUrl },
        { type: "input_image", image_url: competitorDataUrl }
      ]
    }]
  };

  outputItems.push({
    json: { ...item.json, active_prompt: fullPrompt, stage2_prompt: STAGE_2_PROMPT, stage2_full_prompt: fullPrompt, stage2_request_body: body },
    binary: item.binary
  });
}

return outputItems;

