const inputItems = $input.all();

const STAGE_3_PROMPT = `
Use:
- the FIRST attached image as the competitor/reference image for communication strategy
- the SECOND attached image as the real product photo
- the SAFE Generation Brief as the factual execution guide

Create a premium Amazon listing image.

Preserve product accuracy, proportions, materials, and supported claims only.
Understand the competitor image's communication goal but create an original visual execution.
Focus on communicating the same buyer takeaway, not recreating the same scene.

Do NOT closely mimic the competitor image's layout, composition, or spatial structure.

STRICT TEXT RULE:
If the competitor image does NOT use communication text as a major visual element,
the generated image must remain text-free.

Avoid unsupported claims, hallucinated physical details, fake mechanisms.
Aspect ratio: 1:1
`.trim();

function extractStage2Text(value) {
  if (!value) return "";
  if (typeof value === "string") return value;
  if (typeof value === "object") {
    if (typeof value.text === "string") return value.text;
    if (typeof value.output_text === "string") return value.output_text;
    return JSON.stringify(value, null, 2);
  }
  return String(value);
}

return inputItems.map((item, i) => {
  if (!item.binary?.product_image) throw new Error(`product_image binary missing on item ${i}`);
  if (!item.binary?.competitor_image) throw new Error(`competitor_image binary missing on item ${i}`);

  const stage2Text = extractStage2Text(item.json.stage2_safe_generation_brief) || extractStage2Text(item.json.stage2_output_markdown) || "";

  const fullPrompt = `${STAGE_3_PROMPT}\n\n==============================\nSAFE GENERATION BRIEF FROM STAGE 2\n==============================\n\n${stage2Text}\n\n==============================\nFINAL GENERATION CHECK\n==============================`;

  return {
    json: { ...item.json, active_prompt: fullPrompt, stage3_prompt: STAGE_3_PROMPT, stage3_generation_prompt: fullPrompt },
    binary: { ...item.binary, image_1_competitor: item.binary.competitor_image, image_2_product: item.binary.product_image }
  };
});

function findB64(obj) {
  if (!obj) return null;
  if (typeof obj === "string") return null;
  if (obj.b64_json) return obj.b64_json;
  if (Array.isArray(obj)) { for (const item of obj) { const found = findB64(item); if (found) return found; } }
  if (typeof obj === "object") { for (const value of Object.values(obj)) { const found = findB64(value); if (found) return found; } }
  return null;
}

const responses = $input.all();
const requestItems = $("Build Stage 3 - First Image Generation Prompt1").all();
const outputItems = [];

for (let i = 0; i < responses.length; i++) {
  const responseItem = responses[i];
  const originalItem = requestItems[i];
  if (!originalItem) throw new Error(`Matching Stage 3 request item not found for item ${i}`);

  const b64 = findB64(responseItem.json);
  if (!b64) throw new Error(`No b64_json found in Stage 3 response for item ${i}. Preview: ` + JSON.stringify(responseItem.json).slice(0, 1500));

  const cleanB64 = String(b64).replace(/^data:image\/\w+;base64,/, "");
  const buffer = Buffer.from(cleanB64, "base64");
  const filename = `slot_${originalItem.json.slot || "unknown"}_stage3_first_image.png`;
  const outputBinary = await this.helpers.prepareBinaryData(buffer, filename, "image/png");

  outputItems.push({
    json: { ...originalItem.json, stage3_first_image_created: true, stage3_first_image_filename: filename },
    binary: { ...originalItem.binary, previous_output: outputBinary, stage3_first_image: outputBinary }
  });
}

return outputItems;

const inputItems = $input.all();

