const inputItems = $input.all();

const STAGE_5_PROMPT = `
Use:
- the FIRST attached image as the previous generated image and communication reference
- the SECOND attached image as the real product photo
- the redesign direction as the creative guide

Create a more premium and visually distinct Amazon listing image.
The redesign should feel substantially different at first glance while preserving the same buyer takeaway.

Do NOT remove, weaken, or omit important factual information from the previous image.
Information and communication goals are LOCKED.

The redesign should change: layout structure, composition flow, framing, panel structure, spatial hierarchy.
Preserve the MESSAGE, not the geometry.

Background: preserve the previous image's overall presentation category.
If previous is clean/white/minimal, redesign stays clean/white/minimal.
If previous is colorful/lifestyle-rich, redesign preserves that richness.

Text: if previous is text-free, redesign must remain text-free.

Avoid unsupported claims, hallucinated physical details, fake product features.
Aspect ratio: 1:1
`.trim();

function extractText(value) {
  if (!value) return "";
  if (typeof value === "string") return value;
  if (typeof value === "object") {
    if (typeof value.text === "string") return value.text;
    if (typeof value.output_text === "string") return value.output_text;
    return JSON.stringify(value, null, 2);
  }
  return String(value);
}

return inputItems.map((item, i) => {
  if (!item.binary?.product_image) throw new Error(`product_image binary missing on item ${i}`);
  if (!item.binary?.previous_output) throw new Error(`previous_output binary missing on item ${i}`);

  const stage2Text = extractText(item.json.stage2_safe_generation_brief) || extractText(item.json.stage2_output_markdown) || "";
  const stage4Text = extractText(item.json.stage4_design_difference_thinking) || extractText(item.json.stage4_output_markdown) || "";

  const fullPrompt = `${STAGE_5_PROMPT}\n\n==============================\nSAFE GENERATION BRIEF FROM STAGE 2\n==============================\n\n${stage2Text}\n\n==============================\nREDESIGN DIRECTION FROM STAGE 4\n==============================\n\n${stage4Text}\n\n==============================\nFINAL GENERATION CHECK\n==============================`;

  return {
    json: { ...item.json, active_prompt: fullPrompt, stage5_prompt: STAGE_5_PROMPT, stage5_generation_prompt: fullPrompt },
    binary: { ...item.binary, image_1_previous: item.binary.previous_output, image_2_product: item.binary.product_image }
  };
});

function findB64(obj) {
  if (!obj) return null;
  if (typeof obj === "string") return null;
  if (obj.b64_json) return obj.b64_json;
  if (Array.isArray(obj)) { for (const item of obj) { const found = findB64(item); if (found) return found; } }
  if (typeof obj === "object") { for (const value of Object.values(obj)) { const found = findB64(value); if (found) return found; } }
  return null;
}

const responses = $input.all();
const requestItems = $("Build Stage 5 - Final Retry Image Generation Prompt1").all();
const outputItems = [];

for (let i = 0; i < responses.length; i++) {
  const responseItem = responses[i];
  const originalItem = requestItems[i];
  if (!originalItem) throw new Error(`Matching Stage 5 request item not found for item ${i}`);

  const b64 = findB64(responseItem.json);
  if (!b64) throw new Error(`No b64_json found in Stage 5 response for item ${i}. Preview: ` + JSON.stringify(responseItem.json).slice(0, 1500));

  const cleanB64 = String(b64).replace(/^data:image\/\w+;base64,/, "");
  const buffer = Buffer.from(cleanB64, "base64");
  const filename = originalItem.json.output_filename || `generated_image_${originalItem.json.slot || i + 1}.png`;
  const finalBinary = await this.helpers.prepareBinaryData(buffer, filename, "image/png");

  outputItems.push({
    json: {
      slot: originalItem.json.slot,
      slot_key: originalItem.json.slot_key,
      output_filename: filename,
      final_image_created: true
    },
    binary: {
      final_image: finalBinary,
      product_image: originalItem.binary.product_image,
      competitor_image: originalItem.binary.competitor_image
    }
  });
}

return outputItems;

// Aggregate all generated images from all parallel slots into one response.
const items = $input.all();
const images = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary || !item.binary.final_image) continue;
  const buf = await this.helpers.getBinaryDataBuffer(i, 'final_image');
  const mime = item.binary.final_image.mimeType || 'image/png';
  images.push({
    slot: item.json.slot || (i + 1),
    filename: item.json.output_filename || ('generated_image_' + (i + 1) + '.png'),
    data: 'data:' + mime + ';base64,' + buf.toString('base64')
  });
}

images.sort((a, b) => a.slot - b.slot);
return [{ json: { success: true, count: images.length, images } }];
